  1→package project
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→	"time"
  9→)
 10→
 11→const configFile = ".nurge/config.json"
 12→const configLockFile = ".nurge/config.lock"
 13→
 14→// withConfigLock acquires an exclusive file lock on the config lockfile,
 15→// runs fn, then releases the lock. This prevents TOCTOU race conditions
 16→// when multiple processes do Load -> modify -> Write concurrently.
 17→func withConfigLock(fn func() error) error {
 18→	f, err := os.OpenFile(configLockFile, os.O_CREATE|os.O_RDWR, 0600)
 19→	if err != nil {
 20→		return fmt.Errorf("opening config lock: %w", err)
 21→	}
 22→	defer f.Close()
 23→
 24→	if err := flockExclusive(int(f.Fd())); err != nil {
 25→		return fmt.Errorf("acquiring config lock: %w", err)
 26→	}
 27→	defer flockUnlock(int(f.Fd()))
 28→
 29→	return fn()
 30→}
 31→
 32→// ConnectorState holds the state of a single connected service.
 33→type ConnectorState struct {
 34→	Connected   bool   `json:"connected"`
 35→	ConnectedAt string `json:"connected_at,omitempty"`
 36→	Account     string `json:"account,omitempty"`
 37→	Type        string `json:"type"` // "crm" or "email"
 38→}
 39→
 40→// Config is the top-level nurge configuration.
 41→type Config struct {
 42→	Version        int                        `json:"version"`
 43→	CreatedAt      string                     `json:"created_at"`
 44→	Connectors     map[string]ConnectorState  `json:"connectors"`
 45→	SetupCompleted bool                       `json:"setup_completed"`
 46→	Settings       map[string]string          `json:"settings,omitempty"`
 47→}
 48→
 49→// Path returns the path to config.json.
 50→func Path() string {
 51→	return configFile
 52→}
 53→
 54→// Default returns a new Config with default values.
 55→func Default() *Config {
 56→	return &Config{
 57→		Version:        1,
 58→		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 59→		Connectors:     make(map[string]ConnectorState),
 60→		SetupCompleted: false,
 61→	}
 62→}
 63→
 64→// Load reads config from disk.
 65→func Load() (*Config, error) {
 66→	data, err := os.ReadFile(configFile)
 67→	if err != nil {
 68→		return nil, fmt.Errorf("reading config: %w", err)
 69→	}
 70→	var cfg Config
 71→	if err := json.Unmarshal(data, &cfg); err != nil {
 72→		return nil, fmt.Errorf("parsing config: %w", err)
 73→	}
 74→	if cfg.Connectors == nil {
 75→		cfg.Connectors = make(map[string]ConnectorState)
 76→	}
 77→	return &cfg, nil
 78→}
 79→
 80→// Write saves config to disk.
 81→func Write(cfg *Config) error {
 82→	data, err := json.MarshalIndent(cfg, "", "  ")
 83→	if err != nil {
 84→		return fmt.Errorf("marshaling config: %w", err)
 85→	}
 86→	if err := os.WriteFile(configFile, data, 0600); err != nil {
 87→		return fmt.Errorf("writing config: %w", err)
 88→	}
 89→	return nil
 90→}
 91→
 92→// SetConnector updates a connector in the config and saves.
 93→func SetConnector(id, connType, account string) error {
 94→	return withConfigLock(func() error {
 95→		cfg, err := Load()
 96→		if err != nil {
 97→			return err
 98→		}
 99→		cfg.Connectors[id] = ConnectorState{
100→			Connected:   true,
101→			ConnectedAt: time.Now().UTC().Format(time.RFC3339),
102→			Account:     account,
103→			Type:        connType,
104→		}
105→		return Write(cfg)
106→	})
107→}
108→
109→// RemoveConnector removes a connector from config and saves.
110→func RemoveConnector(id string) error {
111→	return withConfigLock(func() error {
112→		cfg, err := Load()
113→		if err != nil {
114→			return err
115→		}
116→		delete(cfg.Connectors, id)
117→		return Write(cfg)
118→	})
119→}
120→
121→// Get returns the value for a settings key, or empty string if not set.
122→func Get(key string) (string, error) {
123→	cfg, err := Load()
124→	if err != nil {
125→		return "", err
126→	}
127→	if cfg.Settings == nil {
128→		return "", nil
129→	}
130→	return cfg.Settings[key], nil
131→}
132→
133→// Set stores a key/value pair in settings and saves the config.
134→func Set(key, value string) error {
135→	return withConfigLock(func() error {
136→		cfg, err := Load()
137→		if err != nil {
138→			return err
139→		}
140→		if cfg.Settings == nil {
141→			cfg.Settings = make(map[string]string)
142→		}
143→		cfg.Settings[key] = value
144→		return Write(cfg)
145→	})
146→}
147→
148→// SetSetupCompleted sets the top-level setup_completed flag and saves.
149→// When marking as complete, also removes the global setup skill -- it's no longer needed.
150→func SetSetupCompleted(completed bool) error {
151→	return withConfigLock(func() error {
152→		cfg, err := Load()
153→		if err != nil {
154→			return err
155→		}
156→		cfg.SetupCompleted = completed
157→		if err := Write(cfg); err != nil {
158→			return err
159→		}
160→		if completed {
161→			removeSetupSkill()
162→		}
163→		return nil
164→	})
165→}
166→
167→// removeSetupSkill deletes the global setup skill directory.
168→// Graceful — ignores errors if already removed.
169→func removeSetupSkill() {
170→	home, err := os.UserHomeDir()
171→	if err != nil {
172→		return
173→	}
174→	os.RemoveAll(filepath.Join(home, ".claude", "skills", "nurge-setup"))
175→}
