 14→var (
 15→	sendTo          string
 16→	sendCc          string
 17→	sendSubject     string
 18→	sendBody        string
 19→	sendSequence    string
 20→	sendCampaign    string
 21→	sendTaskID      string
 22→	sendSendType    string
 23→	sendContactName string
 24→)
 25→
 26→var sendCmd = &cobra.Command{
 27→	Use:   "send",
 28→	Short: "Send an email via Unipile",
 29→	Long:  "Send an email through your connected email account via Convex + Unipile.",
 30→	RunE: func(cmd *cobra.Command, args []string) error {
 31→		if sendSequence != "" && sendTaskID != "" {
 32→			return fmt.Errorf("--sequence and --task-id cannot be used together")
 33→		}
 34→
 35→		// Load auth token
 36→		authFile, err := account.LoadAuth()
 37→		if err != nil || authFile.Token == "" {
 38→			return fmt.Errorf("not logged in. Run: nurge account login")
 39→		}
 40→
 41→		// If --task-id is provided, resolve draft content from local DB for defaults
 42→		if sendTaskID != "" {
 43→			d, err := db.Open()
 44→			if err != nil {
 45→				return fmt.Errorf("opening database: %w", err)
 46→			}
 47→			defer d.Close()
 48→
 49→			task, err := sequence.TaskByID(d, sendTaskID)
 50→			if err != nil {
 51→				return err
 52→			}
 53→			if sendTo == "" {
 54→				sendTo = task.ContactEmail
 55→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 56→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 57→			}
 58→			if sendSubject == "" || sendBody == "" {
 59→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 60→				if err != nil {
 61→					return err
 62→				}
 63→				if sendSubject == "" {
 64→					sendSubject = renderedSubject
 65→				}
 66→				if sendBody == "" {
 67→					sendBody = renderedBody
 68→				}
 69→			}
 70→		}
 71→
 72→		if sendTo == "" {
 73→			return fmt.Errorf("recipient (--to) is required")
 74→		}
 75→		if sendSubject == "" {
 76→			return fmt.Errorf("subject (--subject) is required")
 77→		}
 78→		if sendBody == "" {
 79→			return fmt.Errorf("body (--body) is required")
 80→		}
 81→
 82→		// Build request
 83→		req := account.SendEmailRequest{
 84→			To:       strings.TrimSpace(sendTo),
 85→			Cc:       strings.TrimSpace(sendCc),
 86→			Subject:  sendSubject,
 87→			Body:     sendBody,
 88→			SendType: sequence.NormalizeSendType(sendSendType),
 89→			Sync:     true, // CLI-initiated sends are always sync
 90→			TaskID:   sendTaskID,
 91→		}
 92→
 93→		// Sequence enrollment
 94→		if sendSequence != "" {
 95→			req.SendType = sequence.SendTypeFirstTouch
 96→
 97→			d, err := db.Open()
 98→			if err != nil {
 99→				return fmt.Errorf("opening database: %w", err)
100→			}
101→			defer d.Close()
102→
103→			seqReq := &account.SequenceRequest{
104→				SequenceName: sendSequence,
105→				CampaignName: sendCampaign,
106→				ContactName:  sendContactName,
107→			}
108→
109→			// Best-effort mailbox resolution for Convex
110→			if sendCampaign != "" {
111→				if campaign, cErr := sequence.CampaignByName(d, sendCampaign); cErr == nil {
112→					if mbx, mErr := sequence.CampaignMailbox(d, campaign); mErr == nil && mbx != nil {
113→						seqReq.MailboxID = mbx.ID
114→					}
115→				}
116→			}
117→
118→			// Get steps from built-in template
119→			tmpl, tmplErr := sequence.TemplateByName(d, sendSequence)
120→			if tmplErr == nil {
121→				for _, step := range tmpl.Steps {
122→					if step.StepNumber <= 1 {
123→						continue // skip first touch, that's the current send
124→					}
125→					seqReq.Steps = append(seqReq.Steps, account.SequenceStep{
126→						StepNumber: step.StepNumber,
127→						StepName:   step.Name,
128→						SendType:   step.SendType,
129→						DelayDays:  parseDays(step.Delay),
130→					})
131→				}
132→			}
133→
134→			req.Sequence = seqReq
135→		}
136→
137→		// Call Convex
138→		client := account.NewConvexClient(cmdutil.GetConvexURL())
139→		resp, err := client.SendEmail(authFile.Token, req)
140→		if err != nil {
141→			return fmt.Errorf("send failed: %w", err)
142→		}
143→
144→		if resp.Queued {
145→			fmt.Printf("  \033[33m⏳\033[0m Queued for %s (task: %s)\n", sendTo, resp.TaskID)
146→		} else {
147→			fmt.Printf("  \033[32m✓\033[0m Sent to %s (message ID: %s)\n", sendTo, resp.MessageID)
148→		}
149→
150→		if resp.EnrollmentID != "" {
151→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", sendSequence, resp.EnrollmentID)
152→		}
153→
154→		return nil
155→	},
156→}
