158→func init() {
159→	sendCmd.Flags().StringVar(&sendTo, "to", "", "Recipient email address")
160→	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
161→	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
162→	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
163→	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
164→	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
165→	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
166→	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
167→	sendCmd.Flags().StringVar(&sendContactName, "contact-name", "", "Optional prospect name stored on sequence enrollment")
168→}
