170→// parseDays extracts day count from a duration string like "3d" or "72h".
171→func parseDays(delay string) int {
172→	delay = strings.TrimSpace(delay)
173→	if delay == "" || delay == "0s" {
174→		return 0
175→	}
176→	// Handle "Xd" format
177→	if strings.HasSuffix(delay, "d") {
178→		var d int
179→		fmt.Sscanf(delay, "%dd", &d)
180→		return d
181→	}
182→	// Handle "Xh" format
183→	if strings.HasSuffix(delay, "h") {
184→		var h int
185→		fmt.Sscanf(delay, "%dh", &h)
186→		return h / 24
187→	}
188→	return 3 // default
189→}
