  9→// AutoClassifyResult reports what the heuristic classifier did.
 10→type AutoClassifyResult struct {
 11→	Total        int            `json:"total"`
 12→	Classified   int            `json:"classified"`
 13→	Remaining    int            `json:"remaining"`
 14→	ByClass      map[string]int `json:"by_class"`
 15→	SenderDomain string         `json:"-"` // caller's domain, used internally
 16→}
 17→
 18→// ClassifyAuto applies deterministic heuristics to unclassified emails.
 19→// senderDomain is the user's sending domain (e.g. "acme.com").
 20→// Returns a summary of what was classified and how many remain for Claude.
 21→func ClassifyAuto(d *sql.DB, senderDomain string) (*AutoClassifyResult, error) {
 22→	senderDomain = strings.ToLower(strings.TrimSpace(senderDomain))
 23→
 24→	// Fetch all unclassified emails.
 25→	rows, err := d.Query(`SELECT id, from_email, to_emails, subject, snippet FROM emails WHERE class = 'unclassified'`)
 26→	if err != nil {
 27→		return nil, err
 28→	}
 29→	defer rows.Close()
 30→
 31→	type candidate struct {
 32→		id      string
 33→		from    string
 34→		to      string // JSON array
 35→		subject string
 36→		snippet string
 37→	}
 38→
 39→	var candidates []candidate
 40→	for rows.Next() {
 41→		var c candidate
 42→		var subj, snip sql.NullString
 43→		if err := rows.Scan(&c.id, &c.from, &c.to, &subj, &snip); err != nil {
 44→			return nil, err
 45→		}
 46→		c.subject = subj.String
 47→		c.snippet = snip.String
 48→		candidates = append(candidates, c)
 49→	}
 50→	if err := rows.Err(); err != nil {
 51→		return nil, err
 52→	}
 53→
 54→	// Classify with heuristics.
 55→	var updates []ClassifyUpdate
 56→	result := &AutoClassifyResult{
 57→		Total:   len(candidates),
 58→		ByClass: make(map[string]int),
 59→	}
 60→
 61→	for _, c := range candidates {
 62→		class := classifyHeuristic(c.from, c.to, c.subject, c.snippet, senderDomain)
 63→		if class == "" {
 64→			continue // ambiguous — leave for Claude
 65→		}
 66→		updates = append(updates, ClassifyUpdate{
 67→			ID:           c.id,
 68→			Class:        class,
 69→			Confidence:   0.85,
 70→			ClassifiedBy: "auto",
 71→		})
 72→		result.ByClass[class]++
 73→	}
 74→
 75→	// Batch update in one transaction.
 76→	if len(updates) > 0 {
 77→		if _, err := Classify(d, updates); err != nil {
 78→			return nil, err
 79→		}
 80→	}
 81→
 82→	result.Classified = len(updates)
 83→	result.Remaining = result.Total - result.Classified
 84→	return result, nil
 85→}
 86→
 87→func classifyHeuristic(from, toJSON, subject, snippet, senderDomain string) string {
 88→	fromLower := strings.ToLower(from)
 89→	subjLower := strings.ToLower(subject)
 90→	snipLower := strings.ToLower(snippet)
 91→
 92→	// Parse recipient list.
 93→	var recipients []string
 94→	_ = json.Unmarshal([]byte(toJSON), &recipients)
 95→
 96→	// --- Transactional signals ---
 97→	transactionalPrefixes := []string{
 98→		"noreply@", "no-reply@", "donotreply@", "do-not-reply@",
 99→		"mailer-daemon@", "postmaster@", "notifications@", "notify@",
100→		"support@", "billing@", "receipts@", "invoice@",
101→	}
102→	for _, prefix := range transactionalPrefixes {
103→		if strings.HasPrefix(fromLower, prefix) {
104→			return "transactional"
105→		}
106→	}
107→	// Transactional subjects.
108→	transactionalSubjects := []string{
109→		"password reset", "verify your email", "confirm your",
110→		"your receipt", "your invoice", "your order", "payment confirmation",
111→		"subscription", "account activation", "welcome to",
112→	}
113→	for _, sig := range transactionalSubjects {
114→		if strings.Contains(subjLower, sig) {
115→			return "transactional"
116→		}
117→	}
118→
119→	// --- Internal signals ---
120→	// All recipients share the same domain as sender.
121→	if senderDomain != "" && len(recipients) > 0 {
122→		allInternal := true
123→		for _, r := range recipients {
124→			if !strings.HasSuffix(strings.ToLower(r), "@"+senderDomain) {
125→				allInternal = false
126→				break
127→			}
128→		}
129→		if allInternal {
130→			return "internal"
131→		}
132→	}
133→
134→	// --- Newsletter signals ---
135→	newsletterSubjects := []string{
136→		"newsletter", "digest", "weekly update", "monthly update",
137→		"unsubscribe", "weekly roundup",
138→	}
139→	for _, sig := range newsletterSubjects {
140→		if strings.Contains(subjLower, sig) || strings.Contains(snipLower, sig) {
141→			return "newsletter"
142→		}
143→	}
144→
145→	// --- Personal signals ---
146→	// Single recipient, personal domain, short/casual subject.
147→	personalDomains := map[string]bool{
148→		"gmail.com": true, "yahoo.com": true, "hotmail.com": true,
149→		"outlook.com": true, "icloud.com": true, "aol.com": true,
150→		"protonmail.com": true, "me.com": true, "live.com": true,
151→	}
152→	if len(recipients) == 1 {
153→		parts := strings.SplitN(recipients[0], "@", 2)
154→		if len(parts) == 2 && personalDomains[strings.ToLower(parts[1])] {
155→			// Sender is also from a personal domain → personal.
156→			fromParts := strings.SplitN(from, "@", 2)
157→			if len(fromParts) == 2 && personalDomains[strings.ToLower(fromParts[1])] {
158→				return "personal"
159→			}
160→		}
161→	}
162→
163→	// No confident match — leave for Claude.
164→	return ""
165→}
