143→// StoreConvexEmails stores emails fetched from Convex into local SQLite.
144→// Uses the same StoreEmail function as the Gmail API sync path.
145→func StoreConvexEmails(d *sql.DB, emails []RawMessage) (*SyncResult, error) {
146→	start := time.Now()
147→	result := &SyncResult{Fetched: len(emails)}
148→
