158→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
159→	result.Duration = time.Since(start)
160→
161→	d.Exec(
162→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
163→		 VALUES ('gmail', 'email', ?, ?, ?)
164→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
165→		result.Cursor, result.Cursor, result.Stored,
166→		result.Cursor, result.Cursor, result.Stored,
167→	)
