172→func parseMessage(msg *gm.Message) *RawMessage {
173→	e := &RawMessage{
174→		ID:        msg.Id,
175→		Source:    "gmail",
176→		Direction: "outbound",
177→		ThreadID:  msg.ThreadId,
178→		Snippet:   msg.Snippet,
179→		CcEmails:  "[]",
180→		ToEmails:  "[]",
181→		Labels:    "[]",
182→	}
183→
184→	for _, h := range msg.Payload.Headers {
185→		switch h.Name {
186→		case "Subject":
187→			e.Subject = h.Value
188→		case "From":
189→			e.FromEmail = extractEmail(h.Value)
190→		case "To":
191→			e.ToEmails = emailsToJSON(h.Value)
192→		case "Cc":
193→			e.CcEmails = emailsToJSON(h.Value)
194→		case "Date":
195→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
196→				e.Date = t.UTC().Format(time.RFC3339)
197→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
198→				e.Date = t.UTC().Format(time.RFC3339)
199→			} else {
200→				e.Date = h.Value
201→			}
202→		}
203→	}
204→
205→	if len(msg.LabelIds) > 0 {
206→		labelsJSON, _ := json.Marshal(msg.LabelIds)
207→		e.Labels = string(labelsJSON)
208→	}
209→
210→	return e
211→}
