213→func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
214→	timestamp := e.Date
215→	if direction == "inbound" {
216→		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
217→	}
218→
219→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
220→	for _, recipient := range recipients {
221→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
222→			return err
223→		}
224→	}
225→	return nil
226→}
