  9→// ResumeResult is a compact context snapshot for session hooks (~200 tokens).
 10→type ResumeResult struct {
 11→	Summary       string `json:"summary"`
 12→	TokenEstimate int    `json:"token_estimate"`
 13→}
 14→
 15→// Resume returns a brief working-state summary for compact hook injection.
 16→// It pulls the most recent assembly task, active prospect, key learnings,
 17→// and active sequence info into ~200 tokens.
 18→func Resume(database *sql.DB) (*ResumeResult, error) {
 19→	var parts []string
 20→
 21→	// Active sequences summary
 22→	seqSummary, err := activeSequenceSummary(database)
 23→	if err == nil && seqSummary != "" {
 24→		parts = append(parts, seqSummary)
 25→	}
 26→
 27→	// Recent learnings (last 3, one-liners)
 28→	learnings, err := queryLearningsByTypes(database, nil, 3)
 29→	if err == nil && len(learnings) > 0 {
 30→		var items []string
 31→		for _, l := range learnings {
 32→			// Truncate long learnings
 33→			content := l.Content
 34→			if len(content) > 80 {
 35→				content = content[:77] + "..."
 36→			}
 37→			items = append(items, fmt.Sprintf("[%s] %s", l.Type, content))
 38→		}
 39→		parts = append(parts, "Learnings: "+strings.Join(items, "; "))
 40→	}
 41→
 42→	// Pending reply events
 43→	replyCount, err := pendingReplyCount(database)
 44→	if err == nil && replyCount > 0 {
 45→		parts = append(parts, fmt.Sprintf("Pending replies: %d", replyCount))
 46→	}
 47→
 48→	// Due follow-ups
 49→	dueCount, err := dueFollowUpCount(database)
 50→	if err == nil && dueCount > 0 {
 51→		parts = append(parts, fmt.Sprintf("Due follow-ups: %d", dueCount))
 52→	}
 53→
 54→	summary := strings.Join(parts, "\n")
 55→	if summary == "" {
 56→		summary = "No active context. Start with /nurge:pipeline or /nurge:outbound."
 57→	}
 58→
 59→	return &ResumeResult{
 60→		Summary:       summary,
 61→		TokenEstimate: estimateTokens(summary),
 62→	}, nil
 63→}
 64→
 65→// activeSequenceSummary returns a one-line overview of active sequences.
 66→func activeSequenceSummary(database *sql.DB) (string, error) {
 67→	var activeCount int
 68→	err := database.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = 'active'`).Scan(&activeCount)
 69→	if err != nil {
 70→		return "", err
 71→	}
 72→	if activeCount == 0 {
 73→		return "", nil
 74→	}
 75→
 76→	// Get distinct sequence names
 77→	rows, err := database.Query(
 78→		`SELECT sequence_name, COUNT(*) FROM sequence_enrollments WHERE status = 'active' GROUP BY sequence_name LIMIT 5`,
 79→	)
 80→	if err != nil {
 81→		return "", err
 82→	}
 83→	defer rows.Close()
 84→
 85→	var seqs []string
 86→	for rows.Next() {
 87→		var name string
 88→		var count int
 89→		if err := rows.Scan(&name, &count); err != nil {
 90→			continue
 91→		}
 92→		seqs = append(seqs, fmt.Sprintf("%s(%d)", name, count))
 93→	}
 94→
 95→	return fmt.Sprintf("Active sequences: %s (total: %d)", strings.Join(seqs, ", "), activeCount), rows.Err()
 96→}
 97→
 98→// pendingReplyCount returns the number of unhandled reply events.
 99→func pendingReplyCount(database *sql.DB) (int, error) {
100→	var count int
101→	err := database.QueryRow(`SELECT COUNT(*) FROM reply_events WHERE status = 'open'`).Scan(&count)
102→	return count, err
103→}
104→
105→// dueFollowUpCount returns the number of follow-up tasks due now or overdue.
106→func dueFollowUpCount(database *sql.DB) (int, error) {
107→	var count int
108→	err := database.QueryRow(
109→		`SELECT COUNT(*) FROM follow_up_tasks WHERE status = 'open' AND send_status = 'pending' AND due_at <= datetime('now')`,
110→	).Scan(&count)
111→	return count, err
112→}
