 1→package connector
 2→
 3→import (
 4→	"fmt"
 5→	"io/fs"
 6→	"os"
 7→	"path/filepath"
 8→	"sort"
 9→	"strings"
10→)
11→
12→// LoadRegistry scans bundled definitions and project-local definitions,
13→// returning a merged list. Project-local definitions can override bundled
14→// Tier 2/3 connectors but NOT Tier 1 (email providers).
15→// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
16→func LoadRegistry(projectDir string) ([]ConnectorDef, error) {
17→	defs := make(map[string]ConnectorDef)
18→
19→	// 1. Load bundled definitions
20→	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
21→	if err != nil {
22→		return nil, fmt.Errorf("reading bundled definitions: %w", err)
23→	}
24→	for _, entry := range entries {
25→		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
26→			continue
27→		}
28→		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
29→		if err != nil {
30→			continue
31→		}
32→		yamlDef, err := ParseYAML(data)
33→		if err != nil {
34→			continue // skip invalid bundled defs
35→		}
36→		defs[yamlDef.ID] = ConnectorDef{
37→			ID:       yamlDef.ID,
38→			Name:     yamlDef.Name,
39→			Type:     yamlDef.Type,
40→			Tier:     yamlDef.Tier,
41→			Required: yamlDef.Required,
42→			Def:      yamlDef,
43→		}
44→	}
45→
46→	// 2. Load project-local definitions (override Tier 2/3 only)
47→	if projectDir != "" {
48→		localEntries, err := os.ReadDir(projectDir)
49→		if err == nil { // silently skip if dir doesn't exist
50→			for _, entry := range localEntries {
51→				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
52→					continue
53→				}
54→				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
55→				if err != nil {
56→					continue
57→				}
58→				yamlDef, err := ParseYAML(data)
59→				if err != nil {
60→					continue
61→				}
62→				// Tier 1 connectors cannot be overridden
63→				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
64→					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
65→					continue
66→				}
67→				defs[yamlDef.ID] = ConnectorDef{
68→					ID:       yamlDef.ID,
69→					Name:     yamlDef.Name,
70→					Type:     yamlDef.Type,
71→					Tier:     yamlDef.Tier,
72→					Required: yamlDef.Required,
73→					Def:      yamlDef,
74→				}
75→			}
76→		}
77→	}
78→
79→	// Convert to sorted slice: email first (required), then crm, then enrichment
80→	typeOrder := map[string]int{"email": 0, "crm": 1, "enrichment": 2, "sequencing": 3, "webhook": 4}
81→	result := make([]ConnectorDef, 0, len(defs))
82→	for _, d := range defs {
83→		result = append(result, d)
84→	}
85→	sort.Slice(result, func(i, j int) bool {
86→		oi := typeOrder[result[i].Type]
87→		oj := typeOrder[result[j].Type]
88→		if oi != oj {
89→			return oi < oj
90→		}
91→		return result[i].Name < result[j].Name
92→	})
93→
94→	return result, nil
95→}
