147→		fmt.Println("  By step:")
148→		for stepNum, step := range summary.ByStep {
149→			fmt.Printf("    Step %d: %d total", stepNum, step.Total)
150→			parts := []string{}
151→			if step.Opens > 0 {
152→				parts = append(parts, fmt.Sprintf("%d opens", step.Opens))
153→			}
154→			if step.Clicks > 0 {
155→				parts = append(parts, fmt.Sprintf("%d clicks", step.Clicks))
156→			}
157→			if step.Replies > 0 {
158→				parts = append(parts, fmt.Sprintf("%d replies", step.Replies))
159→			}
160→			if step.Bounces > 0 {
161→				parts = append(parts, fmt.Sprintf("%d bounces", step.Bounces))
162→			}
163→			if step.OOOs > 0 {
164→				parts = append(parts, fmt.Sprintf("%d OOOs", step.OOOs))
165→			}
166→			if len(parts) > 0 {
167→				fmt.Printf(" (%s)", joinParts(parts))
168→			}
169→			fmt.Println()
170→		}
171→
172→		return nil
173→	},
174→}
175→
176→func joinParts(parts []string) string {
177→	result := ""
178→	for i, p := range parts {
179→		if i > 0 {
180→			result += ", "
181→		}
182→		result += p
183→	}
184→	return result
185→}
