 11→async function authenticateRequest(ctx: any, request: Request) {
 12→  const authHeader = request.headers.get("Authorization");
 13→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 14→    return { error: jsonResponse({ error: "Missing auth token" }, 401) };
 15→  }
 16→  const token = authHeader.slice(7);
 17→  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 18→  if (!user) {
 19→    return { error: jsonResponse({ error: "Invalid auth token" }, 401) };
 20→  }
 21→  return { user };
 22→}
