 24→async function getLinkedInAccountIds(ctx: any, userId: string): Promise<string[]> {
 25→  const accounts = await ctx.runQuery(internal.connect.findAllUnipileAccounts, {
 26→    userId,
 27→    provider: "LINKEDIN",
 28→  });
 29→  const connected = accounts.filter((a: any) => a.status === "connected");
 30→  return connected.map((a: any) => a.unipileAccountId);
 31→}
