 33→async function getWorkingLinkedInAccount(ctx: any, userId: string, apiUrl: string, apiKey: string): Promise<string | null> {
 34→  const ids = await getLinkedInAccountIds(ctx, userId);
 35→  if (ids.length === 0) return null;
 36→
 37→  // Also check Unipile directly for all LinkedIn accounts
 38→  try {
 39→    const resp = await fetch(`${apiUrl}/api/v1/accounts`, {
 40→      headers: { "X-API-KEY": apiKey },
 41→    });
 42→    if (resp.ok) {
 43→      const data = await resp.json();
 44→      const linkedinAccounts = (data.items || [])
 45→        .filter((a: any) => a.type === "LINKEDIN" && a.sources?.[0]?.status === "OK")
 46→        .map((a: any) => a.id);
 47→      // Return first account that's both in Convex and active in Unipile
 48→      for (const id of linkedinAccounts) {
 49→        return id; // Use the first active one from Unipile
 50→      }
 51→    }
 52→  } catch (e) {
 53→    // Fall through to Convex accounts
 54→  }
 55→
 56→  return ids[0]; // fallback to first Convex account
 57→}
