 59→async function unipileGet(apiUrl: string, apiKey: string, path: string): Promise<any> {
 60→  const resp = await fetch(`${apiUrl}${path}`, {
 61→    headers: { "X-API-KEY": apiKey },
 62→  });
 63→  if (!resp.ok) {
 64→    const text = await resp.text();
 65→    throw new Error(`Unipile GET ${path} failed (${resp.status}): ${text}`);
 66→  }
 67→  return resp.json();
 68→}
