 36→// buildScopes derives the atom lookup scopes from a contact.
 37→// More specific scopes come first; QueryAtoms returns best match.
 38→func buildScopes(contact *Contact) []string {
 39→	if contact == nil {
 40→		return nil
 41→	}
 42→	var scopes []string
 43→	// Persona/title scope
 44→	if contact.Title != "" {
 45→		scopes = append(scopes, normalizeScope(contact.Title))
 46→	}
 47→	// Tier scope
 48→	if contact.Tier > 0 {
 49→		scopes = append(scopes, fmt.Sprintf("tier_%d", contact.Tier))
 50→	}
 51→	// Industry scope
 52→	if contact.Industry != "" {
 53→		scopes = append(scopes, normalizeScope(contact.Industry))
 54→	}
 55→	// Domain scope (for company-specific atoms)
 56→	if contact.Domain != "" {
 57→		scopes = append(scopes, contact.Domain)
 58→	}
 59→	return scopes
 60→}
 61→
 62→// normalizeScope lowercases and trims for consistent matching.
 63→func normalizeScope(s string) string {
 64→	return strings.ToLower(strings.TrimSpace(s))
 65→}
 66→
 67→// formatContact renders contact information as readable text.
 68→func formatContact(c *Contact) string {
 69→	var lines []string
 70→	lines = append(lines, fmt.Sprintf("**Prospect:** %s", c.Email))
 71→	if c.Name != "" {
 72→		lines = append(lines, fmt.Sprintf("**Name:** %s", c.Name))
 73→	}
 74→	if c.Title != "" {
 75→		lines = append(lines, fmt.Sprintf("**Title:** %s", c.Title))
 76→	}
 77→	if c.Company != "" {
 78→		lines = append(lines, fmt.Sprintf("**Company:** %s", c.Company))
 79→	}
 80→	if c.Domain != "" {
 81→		lines = append(lines, fmt.Sprintf("**Domain:** %s", c.Domain))
 82→	}
 83→	if c.Industry != "" {
 84→		lines = append(lines, fmt.Sprintf("**Industry:** %s", c.Industry))
 85→	}
 86→	if c.FundingStage != "" {
 87→		lines = append(lines, fmt.Sprintf("**Funding:** %s", c.FundingStage))
 88→	}
 89→	if c.CompanySize != "" {
 90→		lines = append(lines, fmt.Sprintf("**Company Size:** %s", c.CompanySize))
 91→	}
 92→	if c.Tier > 0 {
 93→		lines = append(lines, fmt.Sprintf("**Tier:** %d (score: %.1f)", c.Tier, c.TierScore))
 94→	}
 95→	if c.LeadStatus != "" {
 96→		lines = append(lines, fmt.Sprintf("**Lead Status:** %s", c.LeadStatus))
 97→	}
 98→	if c.LinkedInURL != "" {
 99→		lines = append(lines, fmt.Sprintf("**LinkedIn:** %s", c.LinkedInURL))
100→	}
101→	if c.Signals != "" && c.Signals != "[]" {
102→		lines = append(lines, fmt.Sprintf("**Signals:** %s", c.Signals))
103→	}
104→	if c.TechStack != "" && c.TechStack != "[]" {
105→		lines = append(lines, fmt.Sprintf("**Tech Stack:** %s", c.TechStack))
106→	}
107→	return strings.Join(lines, "\n")
108→}
