  9→// Assemble builds the context prompt for a given task and optional prospect.
 10→func Assemble(database *sql.DB, req AssembleRequest) (*AssembleResult, error) {
 11→	if !ValidTaskTypes[req.Task] {
 12→		return nil, fmt.Errorf("unknown task type: %s", req.Task)
 13→	}
 14→	if req.Format == "" {
 15→		req.Format = "markdown"
 16→	}
 17→
 18→	// Check in-memory cache
 19→	cacheKey := string(req.Task) + ":" + req.Prospect
 20→	if cached, ok := defaultCache.Get(cacheKey); ok {
 21→		return &AssembleResult{
 22→			Context:       cached,
 23→			TokenEstimate: estimateTokens(cached),
 24→			Cached:        true,
 25→		}, nil
 26→	}
 27→
 28→	var sections []section
 29→	var atomsLoaded []string
 30→	var directives []string
 31→
 32→	// Load prospect info if applicable
 33→	var contact *Contact
 34→	if req.Prospect != "" {
 35→		c, err := getContact(database, req.Prospect)
 36→		if err != nil {
 37→			return nil, fmt.Errorf("querying contact: %w", err)
 38→		}
 39→		contact = c
 40→	}
 41→
 42→	// Build prospect context section
 43→	if contact != nil {
 44→		sections = append(sections, section{
 45→			heading: "Context",
 46→			body:    formatContact(contact),
 47→		})
 48→	} else if req.Prospect != "" && prospectTasks[req.Task] {
 49→		// Prospect specified but not found -- directive to enrich
 50→		sections = append(sections, section{
 51→			heading: "Context",
 52→			body:    fmt.Sprintf("Prospect: %s (not in contacts -- limited context available)", req.Prospect),
 53→		})
 54→		directives = append(directives, "enrich_required: contact not found in database, run nurge resolve to enrich")
 55→	}
 56→
 57→	// Determine scopes for atom queries based on contact
 58→	scopes := buildScopes(contact)
 59→
 60→	// Load atoms for this task type
 61→	neededAtoms := taskAtomMap[req.Task]
 62→	for _, atomType := range neededAtoms {
 63→		atoms, err := QueryAtoms(database, atomType, scopes...)
 64→		if err != nil {
 65→			return nil, fmt.Errorf("querying %s atoms: %w", atomType, err)
 66→		}
 67→		if len(atoms) > 0 {
 68→			best := pickBestAtom(atoms, scopes)
 69→			content := extractContent(best.Content)
 70→			heading := atomHeading(atomType)
 71→			sections = append(sections, section{heading: heading, body: content})
 72→			atomsLoaded = append(atomsLoaded, fmt.Sprintf("%s/%s", best.AtomType, best.Scope))
 73→			// Touch the atom to track usage
 74→			_ = TouchAtom(database, best.ID)
 75→		}
 76→	}
 77→
 78→	// Research dossier for prospect-facing tasks
 79→	if req.Prospect != "" && prospectTasks[req.Task] {
 80→		dossier, err := GetDossier(database, req.Prospect)
 81→		if err != nil {
 82→			return nil, fmt.Errorf("getting dossier: %w", err)
 83→		}
 84→		if dossier != nil {
 85→			content := extractContent(dossier.Dossier)
 86→			sections = append(sections, section{heading: "Research", body: content})
 87→		} else if contact != nil && contact.Tier > 0 && contact.Tier <= 2 {
 88→			directives = append(directives, "research_required: Tier 1/2 prospect has no research dossier -- run /nurge:research first")
 89→		}
 90→	}
 91→
 92→	// Check for empty enrichment fields on known contacts
 93→	if contact != nil && contact.EnrichedAt == "" && prospectTasks[req.Task] {
 94→		directives = append(directives, "enrich_required: contact has not been enriched -- run nurge resolve to fill in company, title, and signals")
 95→	}
 96→
 97→	// Load recent relevant learnings
 98→	learnings, err := queryRecentLearnings(database, req.Task, 10)
 99→	if err != nil {
100→		return nil, fmt.Errorf("querying learnings: %w", err)
101→	}
102→	if len(learnings) > 0 {
103→		var lines []string
104→		for _, l := range learnings {
105→			lines = append(lines, fmt.Sprintf("- [%s] %s", l.Type, l.Content))
106→		}
107→		sections = append(sections, section{heading: "Recent Learnings", body: strings.Join(lines, "\n")})
108→	}
109→
110→	// Load config context
111→	cfgSection := loadConfigContext(req.Task)
112→	if cfgSection != "" {
113→		sections = append(sections, section{heading: "Configuration", body: cfgSection})
114→	}
115→
116→	// Directives section (placed early so the skill sees it first)
117→	var result strings.Builder
118→	if len(directives) > 0 {
119→		result.WriteString("## Directives\n")
120→		for _, d := range directives {
121→			result.WriteString(fmt.Sprintf("- %s\n", d))
122→		}
123→		result.WriteString("\n")
124→	}
125→
126→	// Render remaining sections
127→	for _, s := range sections {
128→		result.WriteString(fmt.Sprintf("## %s\n%s\n\n", s.heading, s.body))
129→	}
130→
131→	context := strings.TrimSpace(result.String())
132→
133→	// Cache the result
134→	defaultCache.Set(cacheKey, context)
135→
136→	return &AssembleResult{
137→		Context:       context,
138→		TokenEstimate: estimateTokens(context),
139→		AtomsLoaded:   atomsLoaded,
140→		Directives:    directives,
141→		Cached:        false,
142→	}, nil
143→}
144→
145→// InvalidateCache clears the in-memory assembly cache.
146→func InvalidateCache() {
147→	defaultCache.Invalidate()
148→}
