 13→const (
 14→	hubspotTokenPath = ".nurge/connectors/hubspot/token.json"
 15→
 16→	hubspotAuthURL  = "https://app.hubspot.com/oauth/authorize"
 17→	hubspotTokenURL = "https://api.hubapi.com/oauth/v1/token"
 18→)
 19→
 20→// HubSpot OAuth scopes
 21→var hubspotScopes = []string{
 22→	"crm.objects.contacts.read",
 23→	"crm.objects.deals.read",
 24→	"crm.objects.companies.read",
 25→}
 26→
 27→type hubspotConnector struct {
 28→	credentials string // unused for HubSpot but keeps interface consistent
 29→}
 30→
 31→// NewHubSpot creates a new HubSpot connector.
 32→func NewHubSpot(credentials string) Connector {
 33→	return &hubspotConnector{credentials: credentials}
 34→}
 35→
 36→func (h *hubspotConnector) ID() string   { return "hubspot" }
 37→func (h *hubspotConnector) Name() string { return "HubSpot" }
 38→func (h *hubspotConnector) Type() string { return "crm" }
 39→
 40→func (h *hubspotConnector) Connect(ctx context.Context) (*Result, error) {
 41→	// HubSpot OAuth client credentials
 42→	// These come from the HubSpot developer app settings
 43→	clientID := os.Getenv("NURGE_HUBSPOT_CLIENT_ID")
 44→	clientSecret := os.Getenv("NURGE_HUBSPOT_CLIENT_SECRET")
 45→
 46→	if clientID == "" || clientSecret == "" {
 47→		return nil, fmt.Errorf("HubSpot credentials not configured.\n  Set NURGE_HUBSPOT_CLIENT_ID and NURGE_HUBSPOT_CLIENT_SECRET environment variables.\n  Create a HubSpot app at https://developers.hubspot.com/")
 48→	}
 49→
 50→	oauthCfg := &oauth2.Config{
 51→		ClientID:     clientID,
 52→		ClientSecret: clientSecret,
 53→		Scopes:       hubspotScopes,
 54→		Endpoint: oauth2.Endpoint{
 55→			AuthURL:  hubspotAuthURL,
 56→			TokenURL: hubspotTokenURL,
 57→		},
 58→	}
 59→
 60→	// Run shared OAuth flow
 61→	token, err := OAuthFlow(ctx, oauthCfg)
 62→	if err != nil {
 63→		return nil, err
 64→	}
 65→
 66→	// Save token
 67→	if err := os.MkdirAll(".nurge/connectors/hubspot", 0755); err != nil {
 68→		return nil, fmt.Errorf("creating hubspot connector dir: %w", err)
 69→	}
 70→	if err := saveToken(hubspotTokenPath, token); err != nil {
 71→		return nil, fmt.Errorf("saving token: %w", err)
 72→	}
 73→
 74→	// Get account info
 75→	account, err := getHubSpotAccount(ctx, oauthCfg, token)
 76→	if err != nil {
 77→		// Non-fatal — we're connected, just can't get the display name
 78→		account = "connected"
 79→	}
 80→
 81→	return &Result{
 82→		Account: account,
 83→		Token:   token,
 84→	}, nil
 85→}
 86→
 87→// getHubSpotAccount fetches the portal name or account info.
 88→func getHubSpotAccount(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
 89→	client := cfg.Client(ctx, token)
 90→
 91→	// Get access token info which includes the hub domain
 92→	req, err := http.NewRequestWithContext(ctx, "GET",
 93→		fmt.Sprintf("https://api.hubapi.com/oauth/v1/access-tokens/%s", token.AccessToken), nil)
 94→	if err != nil {
 95→		return "", err
 96→	}
 97→
 98→	resp, err := client.Do(req)
 99→	if err != nil {
100→		return "", err
101→	}
102→	defer resp.Body.Close()
103→
104→	if resp.StatusCode != 200 {
105→		return "", fmt.Errorf("HubSpot API returned %d", resp.StatusCode)
106→	}
107→
108→	var info struct {
109→		HubDomain string `json:"hub_domain"`
110→		HubID     int    `json:"hub_id"`
111→		User      string `json:"user"`
112→	}
113→	if err := json.NewDecoder(resp.Body).Decode(&info); err != nil {
114→		return "", err
115→	}
116→
117→	if info.HubDomain != "" {
118→		return info.HubDomain, nil
119→	}
120→	return fmt.Sprintf("hub-%d", info.HubID), nil
121→}
