221→// loadGoogleCredentials loads credentials for google_json source (fallback chain).
222→func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
223→	// 1. Explicit path from --credentials flag
224→	if g.credentials != "" {
225→		data, err := os.ReadFile(g.credentials)
226→		if err != nil {
227→			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
228→		}
229→		return data, nil
230→	}
231→
232→	// 2. Local file in project
233→	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
234→	if data, err := os.ReadFile(localPath); err == nil {
235→		return data, nil
236→	}
237→
238→	// 3. Bundled credentials
239→	if len(BundledCredentials) > 0 {
240→		return BundledCredentials, nil
241→	}
242→
243→	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
244→}
