  5→// Shared Unipile send helper — used by both cron dispatcher and sync httpAction
  6→export async function callUnipileSend(args: {
  7→  accountId: string;
  8→  to: string;
  9→  subject: string;
 10→  body: string;
 11→  replyTo?: string;
 12→}): Promise<
 13→  | { ok: true; messageId: string; providerId: string }
 14→  | { ok: false; error: string; authError: boolean }
 15→> {
 16→  const apiKey = process.env.UNIPILE_API_KEY;
 17→  const apiUrl = process.env.UNIPILE_API_URL;
 18→  if (!apiKey || !apiUrl) {
 19→    return { ok: false, error: "Unipile API key or URL not configured", authError: false };
 20→  }
 21→
 22→  const payload: Record<string, any> = {
 23→    account_id: args.accountId,
 24→    to: [{ identifier: args.to }],
 25→    subject: args.subject,
 26→    body: args.body,
 27→  };
 28→
 29→  if (args.replyTo) {
 30→    payload.reply_to = args.replyTo;
 31→  }
 32→
 33→  const resp = await fetch(`${apiUrl}/api/v1/emails`, {
 34→    method: "POST",
 35→    headers: {
 36→      "X-API-KEY": apiKey,
 37→      "Content-Type": "application/json",
 38→    },
 39→    body: JSON.stringify(payload),
 40→  });
 41→
 42→  if (!resp.ok) {
 43→    const errorText = await resp.text();
 44→    const isAuth = resp.status === 401 || resp.status === 403;
 45→    return {
 46→      ok: false,
 47→      error: isAuth ? `Auth error: ${errorText}` : `Unipile API error ${resp.status}: ${errorText}`,
 48→      authError: isAuth,
 49→    };
 50→  }
 51→
 52→  const result = await resp.json();
 53→  return {
 54→    ok: true,
 55→    messageId: result.id || "",
 56→    providerId: JSON.stringify(result.provider_id || ""),
 57→  };
 58→}
 59→
 60→// Send via Unipile — called by cron dispatcher
 61→export const sendViaUnipile = internalAction({
 62→  args: {
 63→    userId: v.string(),
 64→    taskId: v.string(), // externalId of follow_up_task
 65→    accountId: v.string(), // Unipile account ID
 66→    to: v.string(),
 67→    subject: v.string(),
 68→    body: v.string(),
 69→    replyTo: v.optional(v.string()), // provider_id for threading
 70→  },
 71→  handler: async (ctx, args) => {
 72→    const result = await callUnipileSend({
 73→      accountId: args.accountId,
 74→      to: args.to,
 75→      subject: args.subject,
 76→      body: args.body,
 77→      replyTo: args.replyTo,
 78→    });
 79→
 80→    if (!result.ok) {
 81→      if (result.authError) {
 82→        await ctx.runMutation(internal.send.recordAuthFailure, {
 83→          userId: args.userId,
 84→          taskId: args.taskId,
 85→          mailboxId: "",
 86→          error: result.error,
 87→        });
 88→      } else {
 89→        await ctx.runMutation(internal.send.recordSendFailure, {
 90→          userId: args.userId,
 91→          taskId: args.taskId,
 92→          error: result.error,
 93→        });
 94→      }
 95→      return { ok: false, error: result.error };
 96→    }
 97→
 98→    await ctx.runMutation(internal.send.recordSendSuccess, {
 99→      userId: args.userId,
100→      taskId: args.taskId,
101→      unipileMessageId: result.messageId,
102→      providerId: result.providerId,
103→    });
104→
105→    return { ok: true, messageId: result.messageId, providerId: result.providerId };
106→  },
107→});
108→
109→// Record successful send — updates task, creates send event, advances enrollment
110→export const recordSendSuccess = internalMutation({
111→  args: {
112→    userId: v.string(),
113→    taskId: v.string(),
114→    unipileMessageId: v.string(),
115→    providerId: v.string(),
116→  },
117→  handler: async (ctx, args) => {
118→    const task = await ctx.db
119→      .query("followUpTasks")
120→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
121→      .first();
122→
123→    if (!task) return;
124→
125→    const syncState = await ctx.db
126→      .query("syncState")
127→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
128→      .first();
129→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
130→
131→    // Update task
132→    await ctx.db.patch(task._id, {
133→      status: "completed",
134→      sendStatus: "sent",
135→      completedAt: new Date().toISOString(),
136→      unipileMessageId: args.unipileMessageId,
137→      providerId: args.providerId,
138→      syncVersion: version,
139→    });
140→
141→    // Create send event
142→    const sendEventId = `mse-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
143→    await ctx.db.insert("mailboxSendEvents", {
144→      externalId: sendEventId,
145→      mailboxId: task.mailboxId,
146→      sendType: task.sendType,
147→      sentAt: new Date().toISOString(),
148→      taskId: args.taskId,
149→      enrollmentId: task.enrollmentId,
150→      unipileMessageId: args.unipileMessageId,
151→      providerId: args.providerId,
152→      syncVersion: version,
153→      userId: args.userId,
154→    });
155→
156→    // Advance enrollment
157→    const enrollment = await ctx.db
158→      .query("sequenceEnrollments")
159→      .withIndex("by_external_id", (q) => q.eq("externalId", task.enrollmentId))
160→      .first();
161→
162→    if (enrollment) {
163→      version++;
164→      const newStep = task.stepNumber;
165→      const isComplete = newStep >= enrollment.totalSteps;
166→
167→      await ctx.db.patch(enrollment._id, {
168→        currentStep: newStep,
169→        lastSentAt: new Date().toISOString(),
170→        lastMessageId: args.unipileMessageId,
171→        status: isComplete ? "completed" : enrollment.status,
172→        nextDueAt: isComplete ? "" : enrollment.nextDueAt,
173→        unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
174→        syncVersion: version,
175→      });
176→
177→      // Mark draft as sent
178→      const draft = await ctx.db
179→        .query("sequenceDrafts")
180→        .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
181→        .first();
182→      if (draft) {
183→        await ctx.db.patch(draft._id, {
184→          status: "sent",
185→          syncVersion: version,
186→        });
187→      }
188→    }
189→
190→    // Update sync state
191→    if (syncState) {
192→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
193→    } else {
194→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
195→    }
196→  },
197→});
198→
199→// Record send failure — increment attempt count, set error
200→export const recordSendFailure = internalMutation({
201→  args: {
202→    userId: v.string(),
203→    taskId: v.string(),
204→    error: v.string(),
205→  },
206→  handler: async (ctx, args) => {
207→    const task = await ctx.db
208→      .query("followUpTasks")
209→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
210→      .first();
211→
212→    if (!task) return;
213→
214→    const syncState = await ctx.db
215→      .query("syncState")
216→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
217→      .first();
218→    const version = (syncState?.lastSyncVersion ?? 0) + 1;
219→
220→    const newAttemptCount = task.attemptCount + 1;
221→    const maxRetries = 5;
222→
223→    // Check stale window (48 hours past due)
224→    const dueAt = new Date(task.dueAt).getTime();
225→    const now = Date.now();
226→    const staleWindowMs = 48 * 60 * 60 * 1000;
227→    const isStale = now - dueAt > staleWindowMs;
228→
229→    const isFailed = newAttemptCount >= maxRetries || isStale;
230→
231→    await ctx.db.patch(task._id, {
232→      sendStatus: isFailed ? "failed" : "pending", // back to pending for retry
233→      lastAttemptAt: new Date().toISOString(),
234→      lastError: args.error,
235→      attemptCount: newAttemptCount,
236→      status: isFailed ? "canceled" : task.status,
237→      canceledReason: isFailed
238→        ? isStale
239→          ? "stale: past 48h window"
240→          : `max retries (${maxRetries}) exceeded`
241→        : task.canceledReason,
242→      syncVersion: version,
243→    });
244→
245→    if (syncState) {
246→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
247→    } else {
248→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
249→    }
250→  },
251→});
252→
253→// Record auth failure — mark mailbox as auth_expired, pause enrollment
254→export const recordAuthFailure = internalMutation({
255→  args: {
256→    userId: v.string(),
257→    taskId: v.string(),
258→    mailboxId: v.string(),
259→    error: v.string(),
260→  },
261→  handler: async (ctx, args) => {
262→    const task = await ctx.db
263→      .query("followUpTasks")
264→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
265→      .first();
266→
267→    if (!task) return;
268→
269→    const syncState = await ctx.db
270→      .query("syncState")
271→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
272→      .first();
273→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
274→
275→    // Mark task as failed (don't retry auth errors)
276→    await ctx.db.patch(task._id, {
277→      sendStatus: "failed",
278→      lastError: args.error,
279→      lastAttemptAt: new Date().toISOString(),
280→      syncVersion: version,
281→    });
282→
283→    // Mark mailbox as auth_expired
284→    const mailbox = await ctx.db
285→      .query("mailboxes")
286→      .withIndex("by_external_id", (q) => q.eq("externalId", task.mailboxId))
287→      .first();
288→
289→    if (mailbox) {
290→      version++;
291→      await ctx.db.patch(mailbox._id, {
292→        status: "auth_expired",
293→        syncVersion: version,
294→      });
295→    }
296→
297→    if (syncState) {
298→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
299→    } else {
300→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
301→    }
302→  },
303→});
