641→export const markTaskSent = internalMutation({
642→  args: {
643→    userId: v.string(),
644→    taskId: v.string(),
645→    enrollmentId: v.string(),
646→    mailboxId: v.string(),
647→    sendType: v.string(),
648→    unipileMessageId: v.string(),
649→    providerId: v.string(),
650→  },
651→  handler: async (ctx, args) => {
652→    const task = await ctx.db
653→      .query("followUpTasks")
654→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
655→      .first();
656→    if (!task) return;
657→
658→    const syncState = await ctx.db
659→      .query("syncState")
660→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
661→      .first();
662→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
663→
664→    // Update task
665→    await ctx.db.patch(task._id, {
666→      status: "completed",
667→      sendStatus: "sent",
668→      completedAt: new Date().toISOString(),
669→      unipileMessageId: args.unipileMessageId,
670→      providerId: args.providerId,
671→      syncVersion: version,
672→    });
673→
674→    // Create send event
675→    const sendEventId = `mse-${Date.now()}-${randomSuffix()}`;
676→    await ctx.db.insert("mailboxSendEvents", {
677→      externalId: sendEventId,
678→      mailboxId: args.mailboxId,
679→      sendType: args.sendType,
680→      sentAt: new Date().toISOString(),
681→      taskId: args.taskId,
682→      enrollmentId: args.enrollmentId,
683→      unipileMessageId: args.unipileMessageId,
684→      providerId: args.providerId,
685→      syncVersion: version,
686→      userId: args.userId,
687→    });
688→
689→    // Advance enrollment if applicable
690→    if (args.enrollmentId) {
691→      const enrollment = await ctx.db
692→        .query("sequenceEnrollments")
693→        .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
694→        .first();
695→
696→      if (enrollment) {
697→        version++;
698→        const newStep = task.stepNumber;
699→        const isComplete = newStep >= enrollment.totalSteps;
700→
701→        await ctx.db.patch(enrollment._id, {
702→          currentStep: newStep,
703→          lastSentAt: new Date().toISOString(),
704→          lastMessageId: args.unipileMessageId,
705→          status: isComplete ? "completed" : enrollment.status,
706→          nextDueAt: isComplete ? "" : enrollment.nextDueAt,
707→          unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
708→          syncVersion: version,
709→        });
710→
711→        // Mark draft as sent
712→        const draft = await ctx.db
713→          .query("sequenceDrafts")
714→          .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
715→          .first();
716→        if (draft) {
717→          await ctx.db.patch(draft._id, {
718→            status: "sent",
719→            syncVersion: version,
720→          });
721→        }
722→      }
723→    }
724→
725→    if (syncState) {
726→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
727→    } else {
728→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
729→    }
730→  },
731→});
