771→        version++;
772→        await ctx.db.patch(mailbox._id, {
773→          status: "auth_expired",
774→          syncVersion: version,
775→        });
776→      }
777→    }
778→
779→    if (syncState) {
780→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
781→    } else {
782→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
783→    }
