198→export const claimTask = internalMutation({
199→  args: { taskId: v.string(), userId: v.string() },
200→  handler: async (ctx, args) => {
201→    const task = await ctx.db
202→      .query("followUpTasks")
203→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
204→      .first();
205→    if (!task) return;
206→
207→    await ctx.db.patch(task._id, {
208→      sendStatus: "pending_remote_send",
209→      lastAttemptAt: new Date().toISOString(),
210→    });
211→  },
212→});
213→
214→export const cancelTask = internalMutation({
215→  args: { taskId: v.string(), userId: v.string(), reason: v.string() },
216→  handler: async (ctx, args) => {
217→    const task = await ctx.db
218→      .query("followUpTasks")
219→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
220→      .first();
221→    if (!task) return;
222→
223→    const syncState = await ctx.db
224→      .query("syncState")
225→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
226→      .first();
227→    const version = (syncState?.lastSyncVersion ?? 0) + 1;
228→
229→    await ctx.db.patch(task._id, {
230→      status: "canceled",
231→      sendStatus: "canceled",
232→      canceledReason: args.reason,
233→      syncVersion: version,
234→    });
235→
236→    if (syncState) {
237→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
238→    } else {
239→      await ctx.db.insert("syncState", {
240→        userId: args.userId,
241→        lastSyncVersion: version,
242→      });
243→    }
244→  },
245→});
