271→func (c *ConvexClient) enrichPost(token, path string, payload interface{}) ([]byte, error) {
272→	body, err := json.Marshal(payload)
273→	if err != nil {
274→		return nil, fmt.Errorf("marshaling request: %w", err)
275→	}
276→
277→	client := &http.Client{Timeout: 120 * time.Second}
278→
279→	httpReq, err := http.NewRequest("POST", c.baseURL+path, bytes.NewReader(body))
280→	if err != nil {
281→		return nil, fmt.Errorf("creating request: %w", err)
282→	}
283→	httpReq.Header.Set("Content-Type", "application/json")
284→	httpReq.Header.Set("Authorization", "Bearer "+token)
285→
286→	resp, err := client.Do(httpReq)
287→	if err != nil {
288→		return nil, fmt.Errorf("calling %s: %w", path, err)
289→	}
290→	defer resp.Body.Close()
291→
292→	data, err := io.ReadAll(resp.Body)
293→	if err != nil {
294→		return nil, fmt.Errorf("reading response: %w", err)
295→	}
296→
297→	if resp.StatusCode != 200 {
298→		var errResp struct {
299→			Error string `json:"error"`
300→		}
301→		json.Unmarshal(data, &errResp)
302→		if errResp.Error != "" {
303→			return nil, fmt.Errorf("%s", errResp.Error)
304→		}
305→		return nil, fmt.Errorf("HTTP %d: %s", resp.StatusCode, string(data))
306→	}
307→
308→	return data, nil
309→}
