package email

import (
	"fmt"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/email"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var (
	sendTo          string
	sendCc          string
	sendSubject     string
	sendBody        string
	sendSequence    string
	sendCampaign    string
	sendTaskID      string
	sendSendType    string
	sendContactName string
)

var sendCmd = &cobra.Command{
	Use:   "send",
	Short: "Send an email via Gmail API",
	Long:  "Send an email through your connected Gmail account directly via the Gmail API.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if sendSequence != "" && sendTaskID != "" {
			return fmt.Errorf("--sequence and --task-id cannot be used together")
		}

		// Get connected Gmail account
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}
		gmail, ok := cfg.Connectors["gmail"]
		if !ok || !gmail.Connected {
			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
		}
		fromAddress := gmail.Account

		// Create Gmail API client
		srv, err := email.NewClient("")
		if err != nil {
			return fmt.Errorf("creating Gmail client: %w", err)
		}

		d, err := db.Open()
		if err != nil {
			return fmt.Errorf("opening database: %w", err)
		}
		defer d.Close()

		// If --task-id is provided, resolve draft content from local DB
		if sendTaskID != "" {
			task, err := sequence.TaskByID(d, sendTaskID)
			if err != nil {
				return err
			}
			if sendTo == "" {
				sendTo = task.ContactEmail
			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
			}
			if sendSubject == "" || sendBody == "" {
				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
				if err != nil {
					return err
				}
				if sendSubject == "" {
					sendSubject = renderedSubject
				}
				if sendBody == "" {
					sendBody = renderedBody
				}
			}
		}

		if sendTo == "" {
			return fmt.Errorf("recipient (--to) is required")
		}
		if sendSubject == "" {
			return fmt.Errorf("subject (--subject) is required")
		}
		if sendBody == "" {
			return fmt.Errorf("body (--body) is required")
		}

		// Send via Gmail API
		sent, err := email.Send(srv, fromAddress, email.SendOptions{
			To:      strings.TrimSpace(sendTo),
			Cc:      strings.TrimSpace(sendCc),
			Subject: sendSubject,
			Body:    sendBody,
		})
		if err != nil {
			return fmt.Errorf("send failed: %w", err)
		}

		// Store the sent email locally
		sentAt := time.Now().UTC()
		if storeErr := email.StoreEmail(d, &email.RawMessage{
			ID:        sent.MessageID,
			Source:    "gmail",
			Direction: "outbound",
			ThreadID:  sent.ThreadID,
			Subject:   sendSubject,
			FromEmail: fromAddress,
			ToEmails:  cmdutil.RecipientsJSON(strings.TrimSpace(sendTo)),
			Date:      sentAt.Format(time.RFC3339),
			Labels:    `["SENT"]`,
		}); storeErr != nil {
			fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to store locally: %v\n", storeErr)
		}

		// If --task-id, advance the sequence
		if sendTaskID != "" {
			sendType := sequence.NormalizeSendType(sendSendType)
			if err := sequence.UpdateTaskSendState(d, sendTaskID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to update task: %v\n", err)
			}
			if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
				TaskID:    sendTaskID,
				ThreadID:  sent.ThreadID,
				MessageID: sent.MessageID,
				SentAt:    sentAt,
			}); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to advance sequence: %v\n", err)
			}
			if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
				EnrollmentID: "",
				TaskID:       sendTaskID,
				ContactEmail: strings.TrimSpace(sendTo),
				SendType:     sendType,
				Status:       "sent",
				Subject:      sendSubject,
				MessageID:    sent.MessageID,
				AttemptedAt:  sentAt,
			}); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to log attempt: %v\n", err)
			}
		}

		// Sequence enrollment for first touch
		if sendSequence != "" {
			enrollmentID, enrollErr := enrollInSequence(d, sent, fromAddress, sentAt)
			if enrollErr != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to enroll in sequence: %v\n", enrollErr)
			} else {
				fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", sendSequence, enrollmentID)
			}
		}

		fmt.Printf("  \033[32m✓\033[0m Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
		return nil
	},
}

// enrollInSequence creates a local sequence enrollment and follow-up tasks.
func enrollInSequence(d interface{ Exec(string, ...interface{}) (interface{ LastInsertId() (int64, error) }, error) }, sent *email.SentMessage, fromAddress string, sentAt time.Time) (string, error) {
	// This is a simplified enrollment -- the full enrollment logic
	// lives in the sequence package and handles mailbox resolution,
	// template loading, and follow-up task creation.
	// For now, delegate to the existing sequence.Enroll function.
	return "", fmt.Errorf("local sequence enrollment not yet implemented -- use nurge dispatcher for sequence sends")
}

func init() {
	sendCmd.Flags().StringVar(&sendTo, "to", "", "Recipient email address")
	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
	sendCmd.Flags().StringVar(&sendContactName, "contact-name", "", "Optional prospect name stored on sequence enrollment")
}

// parseDays extracts day count from a duration string like "3d" or "72h".
func parseDays(delay string) int {
	delay = strings.TrimSpace(delay)
	if delay == "" || delay == "0s" {
		return 0
	}
	if strings.HasSuffix(delay, "d") {
		var d int
		fmt.Sscanf(delay, "%dd", &d)
		return d
	}
	if strings.HasSuffix(delay, "h") {
		var h int
		fmt.Sscanf(delay, "%dh", &h)
		return h / 24
	}
	return 3
}

